class Solution:
    def minimumLength(self, s: str) -> int:
        if not s:
            return 0

        # Split the string into runs
        runs = []
        current_char = s[0]
        count = 1
        for c in s[1:]:
            if c == current_char:
                count += 1
            else:
                runs.append((current_char, count))
                current_char = c
                count = 1
        runs.append((current_char, count))

        left = 0
        right = len(runs) - 1

        while left <= right:
            if runs[left][0] == runs[right][0]:
                left += 1
                right -= 1
            else:
                break

        # Calculate the total length of the remaining runs
        total = 0
        for i in range(left, right + 1):
            total += runs[i][1]

        return total

